import { renderToStaticMarkup } from 'react-dom/server'
const products = [
  { id: 1, name: "鍵盤", stock: 3 },
  { id: 2, name: "滑鼠", stock: 0 },
  { id: 3, name: "螢幕", stock: 5 },
];
function Shelf() {
  return (
    <ul>
      {products
        .filter((p) => p.stock > 0)
        .map((p) => <li key={p.id}>{p.name}</li>)}
    </ul>
  );
}
